							data-savepage-src="/themes/mobile4.1/image/icon/customer-next.svg"
							src="data:image/svg+xml;base64,">
					</span>
				</div>
				<div class="line-right"></div>
				<div>
					<span style="color:#65401B; text-align:left;">
						<img class="mx-auto mr-2"
							data-savepage-currentsrc="https://concung.com/themes/mobile4.1/image/icon/customer-point.svg"
							data-savepage-src="/themes/mobile4.1/image/icon/customer-point.svg"
							src="data:image/svg+xml;base64,">
						<span class="font-concung">Con Cưng Xu</span>
