}

/* ─── Banner ─────────────────────────────────────────────────────────────── */
.banner-bg {
	position: absolute;
	top: 0;
	left: 0;
	width: 100%;
	height: auto;
	z-index: -1;
}

/* ─── Wheel wrap ─────────────────────────────────────────────────────────── */
.wheel-wrap {
	position: relative;
	text-align: center;
	margin: 30px auto;
	/* overflow visible để pointer không bị cắt */
	overflow: visible;
	/* Căn giữa và giới hạn max-width */
	max-width: 360px;
	width: 100%;
}

/* ─── Pointer ────────────────────────────────────────────────────────────── */
.wheel-pointer {
	position: absolute;
	/* Đẩy lên đủ cao, không bị cắt */
	top: -20px;
	left: 50%;
	transform: translateX(-50%);
	z-index: 10;
	display: flex;
	flex-direction: column;
	align-items: center;
	/* Không block click vào wheel */
	pointer-events: none;
}

/* ─── Wheel border (vỏ đỏ bên ngoài) ────────────────────────────────────── */
.wheel-border {
	/* Responsive: co lại theo viewport, tối đa 360px */
	width: min(360px, calc(100vw - 32px));
	height: min(360px, calc(100vw - 32px));
	margin: auto;
	position: relative;
	border-radius: 50%;
	background: linear-gradient(145deg, #ff4242, #b80000);
	box-shadow:
		0 14px 28px rgba(0, 0, 0, 0.28),
		inset 0 4px 6px rgba(255, 255, 255, 0.45),
		inset 0 -6px 12px rgba(0, 0, 0, 0.35);
	/* Không cắt pointer */
	overflow: visible;
	/* Cursor pointer để người dùng biết có thể tap */
	cursor: pointer;
}

.wheel-border::before {
	content: "";
	position: absolute;
	inset: 11px;
	border-radius: 50%;
	border: 3px solid #ffd34d;
	z-index: 4;
	pointer-events: none;
}

.wheel-border::after {
	content: "";
	position: absolute;
	inset: 24px;
	border-radius: 50%;
	border: 4px solid #fff;
	z-index: 4;
	pointer-events: none;
}

/* ─── Đã xoá .wheel-lights HTML ─────────────────────────────────────────────
   Đèn được vẽ hoàn toàn bằng canvas trong drawWheel()
